class Solution {
public:
    vector<int> findAllPeople(int n, vector<vector<int>>& meetings, int firstPerson) {
        vector<int> knowSecret = {0, firstPerson};
        sort(meetings.begin(), meetings.end(), [](const vector<int>& a, const vector<int>& b) {
            return a[2] < b[2];
        });
        for (int i = 0; i < meetings.size(); ) {
            int time = meetings[i][2];
            vector<vector<int>> peopleAtTime;
            while (i < meetings.size() && meetings[i][2] == time) {
                peopleAtTime.push_back({meetings[i][0], meetings[i][1]});
                i++;
            }
            unordered_set<int> newKnowSecret;
            for (auto& person : peopleAtTime) {
                bool hasSecret = false;
                for (int j : knowSecret) {
                    if (j == person[0] || j == person[1]) {
                        hasSecret = true;
                        break;
                    }
                }
                if (hasSecret) {
                    newKnowSecret.insert(person[0]);
                    newKnowSecret.insert(person[1]);
                }
            }
            knowSecret.clear();
            for (int j : newKnowSecret) {
                knowSecret.push_back(j);
            }
        }
        sort(knowSecret.begin(), knowSecret.end());
        return knowSecret;
    }
};

